import { useMediaQuery } from 'usehooks-ts';
import { Link } from 'react-router-dom';
import { useTranslation } from 'react-i18next';

import './HomeProjects.css'

import privateImg from '../../assets/projects/private.png'
import publicImg from '../../assets/projects/public.png'
import arrow from '../../assets/icons/arrowhead-up.png'
import { useLocation } from 'react-router-dom';
import useScrollTop from '../../hooks/useScrollTop';

function HomeProjects(props){
    const { t } = useTranslation();
    useScrollTop()

    return(
        <section id="home-projects">
            <div className="home-projects-content-container">
                <Link to='/private' className='project-img-container'>
                    <img className='home-projects-img private' src={privateImg} alt="" loading='lazy'/>
                    <h3 className="home-projects-txt-mobile">{t("private")}</h3>
                    <h3 className="home-projects-txt">{t("private")}</h3>
                </Link>
                
                <Link to='/public' className='project-img-container'>
                    <img className='home-projects-img public' src={publicImg} alt="" loading='lazy'/>
                    <h3 className="home-projects-txt-mobile">{t("public")}</h3>
                    <h3 className="home-projects-txt" >{t("public")}</h3>
                </Link>
            </div>
            { props.anchor ? 
                <a href="#Home">
                    <button className="home-projects-anchor-btn" ><img src={arrow} alt="" /></button>
                </a> : 
                <div/>
            }
        </section>
    )
}

export default HomeProjects;