import Header from './components/Header/Header.jsx';
import './Projects.css'

import Home from './pages/Home/Home.jsx';
import HomeProjects from './pages/HomeProjects/HomeProjects.jsx';
import About from './pages/About/About.jsx';
import Contacts from './pages/Contacts/Contacts.jsx';
import Private from './pages/Private/Private.jsx';
import Public from './pages/Public/Public.jsx';
import FusionInZamoskvorechye from './pages/FusionInZamoskvorechye/FusionInZamoskvorechye.jsx';
import MonochromeMinimalism from './pages/MonochromeMinimalism/MonochromeMinimalism.jsx';
import HighTechOffice from './pages/HighTechOffice/HighTechOffice.jsx';
import WhiteAppartaments from './pages/WhiteAppartaments/WhiteAppartaments.jsx';
import { BrowserRouter, Route, Routes } from "react-router-dom";
import React, { Fragment } from 'react';
import LoftInGeorgia from './pages/LoftInGeorgia/LoftInGeorgia.jsx';


function App() {


    return ( 
        <BrowserRouter>
            <Routes>
                <Route path='/' element={
                    <Fragment>
                        <Home/>
                        <HomeProjects animate={true} anchor={false}/>
                    </Fragment>
                }/>

                <Route path='/about' element={
                    <Fragment>
                        <Header color={'green'}/>
                        <About/>
                    </Fragment>
                }/>

                <Route path='/projects' element={
                    <Fragment>
                        <Header color={'green'}/>
                        <HomeProjects animate={false} anchor={false}/>
                    </Fragment>
                }/>

                <Route path='/contacts' element={
                    <Fragment>
                        <Header color={'green'}/>
                        <Contacts/>
                    </Fragment>
                }/>

                <Route path='/private' element={
                    <Fragment>
                        <Header color={'green'}/>
                        <Private/>
                    </Fragment>
                }/>

                
                <Route path='/fusion' element={
                    <Fragment>
                        <Header color={'green'}/>
                        <FusionInZamoskvorechye/>
                    </Fragment>
                }/>

                <Route path='/white-appartaments' element={
                    <Fragment>
                        <Header color={'green'}/>
                        <WhiteAppartaments/>
                    </Fragment>
                }/>

                <Route path='/loft-in-georgia' element={
                    <Fragment>
                        <Header color={'green'}/>
                        <LoftInGeorgia/>
                    </Fragment>
                }/>

                <Route path='/monochrome' element={
                    <Fragment>
                        <Header color={'green'}/>
                        <MonochromeMinimalism/>
                    </Fragment>
                }/>

                <Route path='/public' element={
                    <Fragment>
                        <Header color={'green'}/>
                        <Public/>
                    </Fragment>
                }/>

                <Route path='/hightech' element={
                    <Fragment>
                        <Header color={'green'}/>
                        <HighTechOffice/>
                    </Fragment>
                }/>
            </Routes>
        </BrowserRouter>
     );
}

export default App;