import {  useRef, useState } from 'react';
import { useEffect } from 'react';
import Sketch from '../../Distortion';
import Header from '../../components/Header/Header'
import mainImage from '../../assets/design/main-new2.jpg'
import contactIcon from '../../assets/design/contact-icon.svg'
import logo from '../../assets/design/Vector.svg'
import { NavLink } from 'react-router-dom';
import './Home.css'
import loader from '../../assets/design/logo.png'
import { useLocation } from 'react-router-dom';
import useScrollTop from '../../hooks/useScrollTop';

function Home(){
    const subtitleRef = useRef(null)
    const [loading, setLoading] = useState(true)
    useScrollTop()

    useEffect(() => {
        new Sketch({
            dom: document.getElementById("homeCanvas")
        });

        setTimeout(() => {
            setLoading(false)
        },1000)
    }, []);

    return(
        <>
            <div className="loader" style={{opacity: loading? 1: 0}}>
                <img className='img-loader' src={loader} alt="" />
            </div>
            <section id="Home">
                <div id="homeCanvas" data-grid="70" data-mouse="0.25" data-strength="0.05" data-relaxation='0.9'>
                    <img src={mainImage} alt=""/>
                </div>
                <div className="home-content">
                    <Header/>
                    <div className="contact-link-conatiner">
                        <NavLink to='/'>
                            <span>contact us</span>
                            <img src={contactIcon} alt="" />
                        </NavLink>
                    </div>
                    <h2 ref={subtitleRef} className='subtitle-home'>interior design studio</h2>
                </div>
            <div className="home-logo-container">
                    <span>Sha</span>
                    <span className='h-l-c-last'>r</span>
                    <img src={logo} alt="" />
            </div>
                {/* <h2 ref={subtitleRef} className='subtitle-home'>{t("home subtitle")}</h2> */}
            </section>
        </> 
    )
}

export default Home;