import './Public.css'
import { Link } from 'react-router-dom';
import { useTranslation } from 'react-i18next'
import HighTechCover from '../../assets/public/Офис Екатеринбург/2.jpg'
import useScrollTop from '../../hooks/useScrollTop';

function Public() {
    useScrollTop()
    const { t } = useTranslation();
    return ( 
        <section id='Public'>
            <div className="public-block">
                <div className="public-content">
                    <Link to='/hightech'>
                        <div className="high-tech">
                            <span className='public-title'>{t("High-tech office")}</span>
                            <img src={HighTechCover} alt="" loading='lazy'/>
                        </div>
                    </Link>
                    <div className="coming-soon">
                        <span className='public-title'>{t("Coming soon")}</span>
                        <img src={HighTechCover} alt="" loading='lazy'/>
                    </div>
                </div>
            </div>
        </section> 
    );
}

export default Public;