import './Private.css'
import { useTranslation } from 'react-i18next'
import fusion from '../../assets/private/fusion.jpeg'
import white from '../../assets/private/white-apartament.jpeg'
import loft from '../../assets/private/loft.jpeg'
import mono from '../../assets/private/monochrome.jpeg'

import PrivateCell from './PrivateCell/PrivateCell'
import useScrollTop from '../../hooks/useScrollTop'

function Private(props){
    const { t } = useTranslation();
    useScrollTop()
    return(
        <section id="Private">
            <div className="private-container">
                <div className="private-table">
                    <PrivateCell 
                        class={'fusion'} 
                        image={fusion} 
                        title={t("Fusion in Zamoskvorechye")} 
                        wide={false} 
                        path={'/fusion'} />

                    <PrivateCell 
                        class={'white'} 
                        image={white} 
                        title={t("White Apartament")} 
                        wide={true}
                        path={'/white-appartaments'}/>

                    <PrivateCell 
                        class={'loft'} 
                        image={loft} 
                        title={t("Loft in Georgia")} 
                        wide={true}
                        path={'/loft-in-georgia'}/>

                    <PrivateCell 
                        class={'mono'} 
                        image={mono} 
                        title={t("Monochrome minimalism")} 
                        wide={false}
                        path={'/monochrome'}/>
                </div>
            </div>
        </section>
    )
}

export default Private