import './MonochromeMinimalism.css'
import { useState } from 'react'
import { useTranslation } from 'react-i18next'
import InfiniteImageSlider from '../../components/InfiniteImageSlider/InfiniteImageSlider.jsx'

import MonochromeGallery1 from '../../assets/private/Дом Подмосковье/ОБЛОЖКА.jpg'
import MonochromeGallery2 from '../../assets/private/Дом Подмосковье/4.jpg'
import MonochromeGallery3 from '../../assets/private/Дом Подмосковье/88.jpg'

import MonochromeGallery4 from '../../assets/private/monochrome.jpeg'
import MonochromeGallery5 from '../../assets/private/Дом Подмосковье/с1.jpg'
import MonochromeGallery6 from '../../assets/private/Дом Подмосковье/с5.jpg'

import MonochromeGallery7 from '../../assets/private/Дом Подмосковье/9.jpg'
import MonochromeGallery8 from '../../assets/private/Дом Подмосковье/22.jpg'

import arrow from '../../assets/icons/arrowhead-up.png'
import TemplateImg from '../../assets/private/Дом Подмосковье/с1.jpg'
import useScrollTop from '../../hooks/useScrollTop.jsx'

function MonochromeMinimalism() {
    useScrollTop()
    const { t } = useTranslation();
    const images = [MonochromeGallery1,
                    MonochromeGallery2,
                    MonochromeGallery3,
                    MonochromeGallery4,
                    MonochromeGallery5,
                    MonochromeGallery6,
                    MonochromeGallery7,
                    MonochromeGallery8]
    const [sliderStartIndex, setSliderStartIndex] = useState(0)
    const [sliderVisible, setSliderVisible] = useState(false)

    const handleMonochromeImageClick = (index) => {
        console.log(1);
        setSliderStartIndex(index)
        setSliderVisible(true)
    }
    
    const closeSlider = () => {
        setSliderVisible(false)
    }

    return ( 
        <section id="Monochrome">
            <div className="monochrome-block monochrome-block-title ">
                <div className="monochrome-title">
                    <span className='monochrome-title-bold'>{t("Monochrome minimalism")}</span>
                    <span>{t("Moscow")}</span>
                    <span>2021</span>
                </div>
                <p className="monochrome-description">
                    {t("monochrome-description")}
                </p>
            </div>
            <div className="monochrome-block monochrome-wide">
                <img src={MonochromeGallery1} className='slider-item-img' alt="" 
                    onClick={()=>{handleMonochromeImageClick(0)}}
                    loading='lazy'/>
            </div>
            <div className="monochrome-block monochrome-grid">
                <div className="grid-el-container grid-1">
                    <img src={TemplateImg} alt="" loading='lazy'/>
                </div>
                <div className="grid-el-container grid-2">
                    <img src={TemplateImg} alt="" loading='lazy'/>
                </div>
                <div className="grid-el-container grid-3">
                    <img src={TemplateImg} alt="" loading='lazy'/>
                </div>
                <div className="grid-el-container grid-4">
                    <img src={TemplateImg} alt="" loading='lazy'/>
                </div>
                <div className="grid-el-container grid-main">
                    <img src={MonochromeGallery2} className='grid-main slider-item-img' alt="" 
                        onClick={()=>{handleMonochromeImageClick(1)}} loading='lazy'/>
                </div>
            </div>
            <div className="monochrome-block monochrome-wide">
                <img src={MonochromeGallery3} className='slider-item-img' alt="" 
                    onClick={()=>{handleMonochromeImageClick(2)}} loading='lazy'/>
            </div>
            <div className="monochrome-block monochrome-triple">
                <img src={MonochromeGallery4} className='slider-item-img' alt="" 
                    onClick={()=>{handleMonochromeImageClick(3)}} loading='lazy'/>
                <img src={MonochromeGallery5} className='slider-item-img' alt="" 
                    onClick={()=>{handleMonochromeImageClick(4)}} loading='lazy'/>
                <img src={MonochromeGallery6} className='slider-item-img' alt="" 
                    onClick={()=>{handleMonochromeImageClick(5)}} loading='lazy'/>
            </div>
            <div className="monochrome-block monochrome-double">
                <img src={MonochromeGallery7} className='slider-item-img' alt="" 
                    onClick={()=>{handleMonochromeImageClick(6)}} loading='lazy'/>
                <img src={MonochromeGallery8} className='slider-item-img' alt="" 
                    onClick={()=>{handleMonochromeImageClick(7)}} loading='lazy'/>
            </div>
            <a href="#Monochrome">
                <button className="home-projects-anchor-btn" ><img src={arrow} alt="" /></button>
            </a>
            {sliderVisible ? <InfiniteImageSlider content={images} startIndex={sliderStartIndex} closeFunction={closeSlider}/> : <></>}
        </section> 
    );
}

export default MonochromeMinimalism;