import './WhiteAppartaments.css'
import whiteGallery1 from '../../assets/private/Белые аппартаменты/1.jpg'
import whiteGallery2 from '../../assets/private/Белые аппартаменты/2.jpg'
import whiteGallery3 from '../../assets/private/Белые аппартаменты/3.jpg'
import whiteGallery6 from '../../assets/private/Белые аппартаменты/6.jpg'
import whiteGallery7 from '../../assets/private/Белые аппартаменты/7.jpg'
import whiteGallery8 from '../../assets/private/Белые аппартаменты/8.jpg'
import whiteGallery9 from '../../assets/private/Белые аппартаменты/9.jpg'
import whiteGallery10 from '../../assets/private/Белые аппартаменты/10.jpg'
import whiteGallery11 from '../../assets/private/Белые аппартаменты/11.jpg'

import InfiniteImageSlider from '../../components/InfiniteImageSlider/InfiniteImageSlider'
import { useState } from 'react'
import { useTranslation } from 'react-i18next';
import useScrollTop from '../../hooks/useScrollTop'

function WhiteAppartaments() {
    useScrollTop()
    const { t } = useTranslation();
    const images = [whiteGallery1,
         whiteGallery2,
         whiteGallery3,
         whiteGallery6,
         whiteGallery7,
         whiteGallery8,
         whiteGallery9,
         whiteGallery10,
         whiteGallery11]
    const [sliderStartIndex, setSliderStartIndex] = useState(0)
    const [sliderVisible, setSliderVisible] = useState(false)

    const handleWhiteImageClick = (index) => {
        setSliderStartIndex(index)
        setSliderVisible(true)
    }
    
    const closeSlider = () => {
            setSliderVisible(false)
    }

    return ( 
        <section id="White">
            <div className="project-row">
                <div className="row-left">
                    <div className="project-title-container">
                        <span className="white-title" style={{fontWeight:'bolder'}}>{t("White Apartament")}</span>
                        <span className="white-city">{t("Yekaterinburg")}</span>
                        <span className="white-year"> 2023 </span>
                    </div>
                    <p className="project-description-text">
                        {t("white-decription-text")}
                    </p>
                </div>
                <div className="row-right">
                    <img className='project-img'  src={whiteGallery1} alt="" onClick={()=> 
                                handleWhiteImageClick(0)} loading='lazy'/>
                </div>
            </div>
            <div className="project-row wr-center">
                <div className="row-left">
                    <img className='project-img'  src={whiteGallery3} alt="" onClick={()=> 
                                handleWhiteImageClick(2)} loading='lazy'/>
                </div>
                <div className="row-right">
                    <div className="project-double">
                        <img className='project-img'  src={whiteGallery9} alt="" onClick={()=> 
                                handleWhiteImageClick(8)} loading='lazy'/>
                        <img className='project-img'  src={whiteGallery8} alt="" onClick={()=> 
                                handleWhiteImageClick(7)} loading='lazy'/>
                    </div>
                </div>
            </div>
            <div className="project-row" style={{marginTop:100}}>
                <div className="row-left">
                    <img className='project-img'  src={whiteGallery2} alt="" onClick={()=> 
                            handleWhiteImageClick(1)} loading='lazy'/>
                </div>
                <div className="row-right">
                    <p className='white-extra-text-1'>
                        {t("white-extra-text-1")}
                    </p>
                </div>
            </div>
            <div className="project-row" style={{marginTop:100}}>
                <div className="row-left">
                    <p className='white-extra-text-2'>
                        {t("white-extra-text-2")}
                    </p>
                </div>
                <div className="row-right">
                    <img className='project-img'  src={whiteGallery7} alt="" onClick={()=> 
                                handleWhiteImageClick(6)} loading='lazy'/>
                </div>
            </div>
            <div className="project-row" style={{marginTop:50}}>
                <div className="row-left">
                    <div className="project-double" style={{marginTop:260}}>
                        <img className='project-img'  src={whiteGallery10} alt="" onClick={()=> 
                                handleWhiteImageClick(9)} loading='lazy'/>
                        <img className='project-img'  src={whiteGallery11} alt="" onClick={()=> 
                                handleWhiteImageClick(10)} loading='lazy'/>
                    </div>
                </div>
                <div className="row-right">
                    <img className='project-img' src={whiteGallery6} alt="" onClick={()=> 
                                handleWhiteImageClick(5)} loading='lazy'/>
                </div>
            </div>
            {sliderVisible ? <InfiniteImageSlider content={images} startIndex={sliderStartIndex} closeFunction={closeSlider}/> : <></> }
        </section> 
    );
}

export default WhiteAppartaments;